import{_ as r,c as i,d as l,e,f as o,w as n,h as t,t as d,j as u,l as c}from"./index-DlZ0_hBn.js";const p={class:"legal"},h={class:"page-top"},f={class:"muted footer-links"},b="July 14, 2026",y={__name:"TermsPage",setup(m){return(v,a)=>{const s=c("router-link");return i(),l("div",p,[e("div",h,[o(s,{to:"/",class:"home-link"},{default:n(()=>[...a[0]||(a[0]=[t("‹ Home",-1)])]),_:1})]),a[4]||(a[4]=e("h1",null,"Terms of service",-1)),e("p",{class:"muted updated"},"Last updated "+d(b)),a[5]||(a[5]=u('<p data-v-312ab7ef> These are the terms for using SaunaSpeak (saunaspeak.com). Short version: be a normal human, the free path stays free, subscriptions cancel cleanly, and the AI characters are language practice - not advisors. </p><h2 data-v-312ab7ef>The service</h2><p data-v-312ab7ef> SaunaSpeak teaches spoken Finnish through short daily sessions, spaced repetition, audio and AI conversation practice. The core learning path is free. Löyly+ is an optional paid subscription that adds AI features (Sauna Chat, Situations, AI feedback, weekly insights). </p><h2 data-v-312ab7ef>Your account</h2><ul data-v-312ab7ef><li data-v-312ab7ef>You need to be at least 13 years old (or the digital-consent age in your country).</li><li data-v-312ab7ef>Keep your password to yourself; you&#39;re responsible for what happens under your login.</li><li data-v-312ab7ef>One account per person - progress and streaks are personal by design.</li></ul><h2 data-v-312ab7ef>Löyly+ subscriptions</h2><ul data-v-312ab7ef><li data-v-312ab7ef>Billed monthly (€4.99) or yearly (€39.99) through Stripe, renewing automatically until cancelled.</li><li data-v-312ab7ef>Cancel any time from your profile - you keep access until the end of the period you&#39;ve paid for, and are not charged again.</li><li data-v-312ab7ef>If a payment fails, Löyly+ features pause until it&#39;s settled; your learning data is never touched.</li><li data-v-312ab7ef>Prices may change; existing subscribers get clear notice before any change affects them.</li></ul><h2 data-v-312ab7ef>Fair use</h2><ul data-v-312ab7ef><li data-v-312ab7ef>Don&#39;t abuse the AI features (automated scraping, bulk generation, attempting to make the characters produce harmful content). Daily message caps exist to keep the service affordable for everyone.</li><li data-v-312ab7ef>Don&#39;t try to break, overload or reverse the service.</li><li data-v-312ab7ef>Lesson content, audio and the Väinö character are SaunaSpeak&#39;s; personal, non-commercial use only.</li></ul><h2 data-v-312ab7ef>The honest disclaimers</h2><ul data-v-312ab7ef><li data-v-312ab7ef>AI replies are generated by language models and can be wrong. Corrections aim to teach everyday spoken Finnish, not certified translation. Double-check anything important.</li><li data-v-312ab7ef>The service is provided &quot;as is&quot; - we work hard on uptime and data safety but can&#39;t guarantee either perfectly. Our total liability is capped at what you&#39;ve paid us in the last 12 months.</li><li data-v-312ab7ef>We may update features and these terms; material changes will be announced in the app or by email.</li></ul><h2 data-v-312ab7ef>Ending things</h2><p data-v-312ab7ef> You can delete your account (and export your data first) from your profile at any time. We can suspend accounts that break these terms, with a warning unless the abuse is severe. </p><h2 data-v-312ab7ef>Contact</h2><p data-v-312ab7ef><a href="mailto:mail@saunaspeak.com" data-v-312ab7ef>mail@saunaspeak.com</a> - a human reads it. </p>',15)),e("p",f,[o(s,{to:"/privacy"},{default:n(()=>[...a[1]||(a[1]=[t("Privacy policy",-1)])]),_:1}),a[3]||(a[3]=t(" · ",-1)),o(s,{to:"/"},{default:n(()=>[...a[2]||(a[2]=[t("Home",-1)])]),_:1})])])}}},k=r(y,[["__scopeId","data-v-312ab7ef"]]);export{k as default};
